import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';
import { UserRepository } from './user.repository';
import { EmployeeRepository } from '../employee/employee.repository';
import { User } from './user.entity';

export interface IAuthService {
  login(username: string, password: string): Promise<string>;
}

export class AuthService implements IAuthService {
  constructor(
    private userRepository: UserRepository,
    private employeeRepository: EmployeeRepository
  ) {}

  async login(username: string, password: string): Promise<string> {
    const user = await this.userRepository.findByUsername(username);
    if (!user) {
      throw new Error('Invalid credentials');
    }

    const employee = await this.employeeRepository.findById(user.employeeId);
    if (!employee || employee.status !== 'active') {
      throw new Error('Employee account is not active');
    }

    const isValid = await bcrypt.compare(password, user.passwordHash);
    if (!isValid) {
      throw new Error('Invalid credentials');
    }

    const token = jwt.sign(
      { sub: user.id, employeeId: user.employeeId, role: user.role },
      process.env.JWT_SECRET || 'default-secret',
      { expiresIn: '1h' }
    );
    return token;
  }
}","File: src/modules/auth/auth.middleware.ts
import { FastifyRequest, FastifyReply } from 'fastify';
import jwt from 'jsonwebtoken';

export interface JwtPayload {
  sub: string;
  employeeId: string;
  role: 'employee' | 'manager';
}

declare module 'fastify' {
  interface FastifyRequest {
    user?: JwtPayload;
  }
}

export async function authenticateJWT(
  request: FastifyRequest,
  reply: FastifyReply
): Promise<void> {
  const authHeader = request.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    reply.status(401).send({ error: 'Missing or invalid token' });
    return;
  }

  const token = authHeader.split(' ')[1];
  try {
    const decoded = jwt.verify(
      token,
      process.env.JWT_SECRET || 'default-secret'
    ) as JwtPayload;
    request.user = decoded;
  } catch (err) {
    reply.status(401).send({ error: 'Invalid or expired token' });
  }
}

export function requireRole(...roles: string[]) {
  return async (request: FastifyRequest, reply: FastifyReply): Promise<void> => {
    if (!request.user || !roles.includes(request.user.role)) {
      reply.status(403).send({ error: 'Insufficient permissions' });
    }
  };
}","File: src/modules/auth/auth.controller.ts
